-- 0047 : modules d'ANGLAIS pour college (6e-3e) et lycee (Seconde/Premiere/
-- Terminale, memes themes pour les series A/C/D), extraits des syllabi officiels.
-- Structure d'abord (chapitres vides). Puis sigle ANG N · sur TOUT l'anglais.

on conflict (id) do nothing;

-- Uniformise les sigles sur toutes les matieres anglais (existant + nouveau)
update chapters set title = 'ANG ' || sort_order || ' · ' ||
  regexp_replace(title, '^[[:alpha:]]{1,6}[[:space:]]*[0-9]+[[:space:]]*·[[:space:]]*', '')
  where subject_key = 'anglais';
